using System.ComponentModel;
using System.Text;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Logging;
using OpenAI;

// --- Configuration ---

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- DI & Chat Client ---

var services = new ServiceCollection();
services.AddLogging(b => b.AddConsole().SetMinimumLevel(LogLevel.Warning));

services.AddChatClient(builder => builder
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

var provider = services.BuildServiceProvider();
var chatClient = provider.GetRequiredService<IChatClient>();

// --- Tools ---

var notebook = new Notebook();

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query to look up on the web")] string query) =>
        {
            return WebSearch.SearchAsync(query);
        },
        "web_search",
        "Searches the web for the given query and returns a list of result snippets. " +
        "Use this to find information about a topic."),

    AIFunctionFactory.Create(
        ([Description("A concise note capturing a key finding")] string note,
         [Description("The source URL or description for this finding")] string source) =>
        {
            notebook.Add(note, source);
            return $"Note saved. You now have {notebook.Count} note(s).";
        },
        "save_note",
        "Saves a research note with its source for later use in the summary. " +
        "Call this every time you discover an important fact."),

    AIFunctionFactory.Create(
        () => notebook.GetAllFormatted(),
        "get_notes",
        "Returns all previously saved research notes. " +
        "Use this before writing the final summary to review what you've collected."),
};

// --- Agent ---

const string instructions = """
    You are a research agent. When the user gives you a topic:

    1. Plan 3-5 diverse search queries that cover different angles of the topic.
    2. Execute each query using the web_search tool.
    3. For every useful finding, call save_note with a concise note and its source.
    4. After all searches are complete, call get_notes to review your collected findings.
    5. Write a well-structured summary with:
       - An introduction to the topic
       - Key findings organized by theme
       - A "Sources" section listing all sources

    Be thorough but concise. Prefer recent and authoritative sources.
    """;

var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An agent that researches topics by searching the web and summarizing findings.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 4096,
            Tools = [.. tools],
        },
    });

// --- Run ---

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

string topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptUser();

Console.WriteLine();
Console.WriteLine($"Researching: {topic}");
Console.WriteLine(new string('─', 50));

var runOptions = new ChatClientAgentRunOptions(new ChatOptions { Instructions = instructions });
var response = await agent.RunAsync(topic, options: runOptions);

Console.WriteLine();
Console.WriteLine(response.Text);
Console.WriteLine();
Console.WriteLine($"[Notes collected: {notebook.Count} | " +
                  $"Completion reason: {response.FinishReason}]");

// --- Helpers ---

static string PromptUser()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrEmpty(input)
        ? throw new InvalidOperationException("A research topic is required.")
        : input;
}

// --- Notebook (note-taking tool state) ---

sealed class Notebook
{
    private readonly List<(string Note, string Source)> _notes = [];

    public int Count => _notes.Count;

    public void Add(string note, string source) => _notes.Add((note, source));

    public string GetAllFormatted()
    {
        if (_notes.Count == 0)
            return "No notes saved yet.";

        var sb = new StringBuilder();
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i].Note}");
            sb.AppendLine($"    Source: {_notes[i].Source}");
        }

        return sb.ToString();
    }
}

// --- Simulated web search (replace with a real search API for production) ---

static class WebSearch
{
    private static readonly Dictionary<string, string[]> s_results = new(StringComparer.OrdinalIgnoreCase)
    {
        ["renewable energy trends 2025"] =
        [
            "Solar power costs dropped 90% since 2010, making it the cheapest electricity source in most countries. (Source: IRENA Global Report 2025)",
            "Global renewable energy capacity reached 4,500 GW in 2024, with solar and wind accounting for 75% of new installations. (Source: IEA Renewables 2025)",
            "Battery storage deployments tripled year-over-year, reaching 120 GWh globally. (Source: BloombergNEF Energy Storage Outlook)",
        ],
        ["solar energy advances"] =
        [
            "Perovskite-silicon tandem solar cells achieved 33.9% efficiency in lab tests, a new world record. (Source: Nature Energy, Jan 2025)",
            "Floating solar farms are expanding rapidly in Asia, with 50 GW of capacity planned across 12 countries. (Source: World Bank Solar Report)",
            "Agrivoltaics — combining farming with solar panels — increased crop yields by 10-30% while generating electricity. (Source: Fraunhofer ISE Study)",
        ],
        ["wind energy developments"] =
        [
            "Offshore wind capacity surpassed 100 GW globally, led by the UK, China, and the Netherlands. (Source: GWEC Wind Report 2025)",
            "Next-generation 20 MW wind turbines entered production, with rotors spanning 280 meters. (Source: Vestas Press Release)",
            "Airborne wind energy systems using tethered kites reached commercial viability in pilot projects. (Source: Makani/Google X Research)",
        ],
        ["energy storage battery technology"] =
        [
            "Sodium-ion batteries entered mass production, offering 30% lower costs than lithium-ion for grid storage. (Source: CATL Announcement)",
            "Iron-air batteries demonstrated 100-hour discharge duration at grid scale, addressing long-duration storage needs. (Source: Form Energy Pilot Data)",
            "Vehicle-to-grid (V2G) technology enabled EVs to supply 15 GW of peak power back to grids in Europe. (Source: EU Energy Agency Report)",
        ],
        ["climate policy carbon reduction"] =
        [
            "145 countries now have legally binding net-zero targets, covering 92% of global GDP. (Source: Climate Action Tracker 2025)",
            "Global carbon pricing mechanisms generated $120 billion in revenue in 2024, up 40% from 2023. (Source: World Bank Carbon Pricing Dashboard)",
            "The EU Carbon Border Adjustment Mechanism (CBAM) went into full effect, reshaping international trade in steel and cement. (Source: European Commission)",
        ],
        ["artificial intelligence 2025"] =
        [
            "AI models surpassed human-level performance on professional benchmarks in law, medicine, and engineering. (Source: Stanford HAI Index 2025)",
            "Enterprise AI adoption reached 78%, with the largest gains in healthcare diagnostics and supply chain optimization. (Source: McKinsey Global AI Survey)",
            "Open-source AI models closed the gap with proprietary systems, with several achieving state-of-the-art results. (Source: Hugging Face Open LLM Leaderboard)",
        ],
        ["quantum computing progress"] =
        [
            "IBM and Google demonstrated quantum error correction at scale, a critical milestone toward fault-tolerant quantum computing. (Source: Nature, March 2025)",
            "Quantum computers solved optimization problems 100x faster than classical supercomputers in logistics benchmarks. (Source: D-Wave Case Studies)",
            "Post-quantum cryptography standards were finalized by NIST and adoption began across government systems. (Source: NIST PQC Standardization)",
        ],
    };

    public static Task<string> SearchAsync(string query)
    {
        // Find the best matching result set using keyword overlap
        var bestMatch = s_results
            .OrderByDescending(kv => query
                .Split(' ', StringSplitOptions.RemoveEmptyEntries)
                .Count(word => kv.Key.Contains(word, StringComparison.OrdinalIgnoreCase)))
            .First();

        var sb = new StringBuilder();
        sb.AppendLine($"Search results for: \"{query}\"");
        sb.AppendLine();
        foreach (var result in bestMatch.Value)
        {
            sb.AppendLine($"• {result}");
        }

        return Task.FromResult(sb.ToString());
    }
}

