26. {
27.     AIFunctionFactory.Create(
28.         ([Description("The search query to look up on the web")] string query) =>
29.         {
30.             return WebSearch.SearchAsync(query);
31.         },
32.         "web_search",
33.         "Searches the web for the given query and returns a list of result snippets. " +
34.         "Use this to find information about a topic."),
35. 
36.     AIFunctionFactory.Create(
37.         ([Description("A concise note capturing a key finding")] string note,
38.          [Description("The source URL or description for this finding")] string source) =>
39.         {
40.             notebook.Add(note, source);
41.             return $"Note saved. You now have {notebook.Count} note(s).";
42.         },
43.         "save_note",
44.         "Saves a research note with its source for later use in the summary. " +
45.         "Call this every time you discover an important fact."),
46. 
47.     AIFunctionFactory.Create(
48.         () => notebook.GetAllFormatted(),
49.         "get_notes",
50.         "Returns all previously saved research notes. " +
51.         "Use this before writing the final summary to review what you've collected."),
52. };
53. 
54. // --- Agent ---
55. 
56. const string instructions = """
57.     You are a research agent. When the user gives you a topic:
58. 
59.     1. Plan 3-5 diverse search queries that cover different angles of the topic.
60.     2. Execute each query using the web_search tool.
61.     3. For every useful finding, call save_note with a concise note and its source.
62.     4. After all searches are complete, call get_notes to review your collected findings.
63.     5. Write a well-structured summary with:
64.        - An introduction to the topic
65.        - Key findings organized by theme
66.        - A "Sources" section listing all sources
67. 
68.     Be thorough but concise. Prefer recent and authoritative sources.
69.     """;
70. 
71. var agent = new ChatClientAgent(
72.     chatClient,
73.     new ChatClientAgentOptions
74.     {
75.         Name = "ResearchAgent",
76.         Description = "An agent that researches topics by searching the web and summarizing findings.",
77.         ChatOptions = new ChatOptions
78.         {
79.             Temperature = 0f,
80.             MaxOutputTokens = 4096,
81.             Tools = [.. tools],
82.         },
83.     });
84. 
85. // --- Run ---
86. 
87. Console.WriteLine("╔══════════════════════════════════════╗");
88. Console.WriteLine("║       Research Agent (MAF + MEAI)    ║");
89. Console.WriteLine("╚══════════════════════════════════════╝");
90. Console.WriteLine();
91. 
92. string topic = args.Length > 0
93.     ? string.Join(' ', args)
94.     : PromptUser();
95. 
96. Console.WriteLine();
97. Console.WriteLine($"Researching: {topic}");
98. Console.WriteLine(new string('─', 50));
99. 
100. var runOptions = new ChatClientAgentRunOptions(new ChatOptions { Instructions = instructions });
101. var response = await agent.RunAsync(topic, options: runOptions);
102. 
103. Console.WriteLine();
104. Console.WriteLine(response.Text);
105. Console.WriteLine();
106. Console.WriteLine($"[Notes collected: {notebook.Count} | " +
107.                   $"Completion reason: {response.FinishReason}]");
108. 
109. // --- Helpers ---
110. 
111. static string PromptUser()
112. {
113.     Console.Write("Enter a research topic: ");
114.     var input = Console.ReadLine()?.Trim();
115.     return string.IsNullOrEmpty(input)
116.         ? throw new InvalidOperationException("A research topic is required.")
117.         : input;
118. }
